import{c as a,Q as n,j as e,m as i}from"./chunks/framework.iD28w_5a.js";const b=JSON.parse('{"title":"030 #GP 异常排查：ISR 栈对齐违反 System V ABI","description":"","frontmatter":{"title":null},"headers":[],"relativePath":"notes/030/gp_fault_stack_alignment.md","filePath":"notes/030/gp_fault_stack_alignment.md","lastUpdated":1779686691000}'),p={name:"notes/030/gp_fault_stack_alignment.md"};function l(r,s,t,d,c,h){return n(),e("div",null,[...s[0]||(s[0]=[i(`<h1 id="_030-gp-异常排查-isr-栈对齐违反-system-v-abi" tabindex="-1">030 #GP 异常排查：ISR 栈对齐违反 System V ABI <a class="header-anchor" href="#_030-gp-异常排查-isr-栈对齐违反-system-v-abi" aria-label="Permalink to &quot;030 #GP 异常排查：ISR 栈对齐违反 System V ABI&quot;">​</a></h1><h2 id="现象" tabindex="-1">现象 <a class="header-anchor" href="#现象" aria-label="Permalink to &quot;现象&quot;">​</a></h2><p><code>make run</code> 启动后，在打印 <code>[GUI] ===== Milestone 030: GUI Window Manager =====</code> 后立即触发 #GP：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>==== EXCEPTION: #GP (vector 13) ====</span></span>
<span class="line"><span>  RIP   = 0xFFFFFFFF81001DBB   CS  = 0x0010</span></span>
<span class="line"><span>  RFLAGS= 0x0000000000010002</span></span>
<span class="line"><span>  RSP   = 0xFFFF800008047EF8   SS  = 0x0018</span></span>
<span class="line"><span>  RAX=0x0000000000000041  RBX=0x0000000000000000</span></span>
<span class="line"><span>  RCX=0x00000000FFFFFF01  RDX=0x0000000000000003</span></span>
<span class="line"><span>  RSI=0x0000000000000001  RDI=0x0000000000000000</span></span>
<span class="line"><span>  ...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h2 id="触发路径" tabindex="-1">触发路径 <a class="header-anchor" href="#触发路径" aria-label="Permalink to &quot;触发路径&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gui_start()</span></span>
<span class="line"><span>  → Mouse::init()            // 操作 PS/2 控制器 (0xA8, 0x20, 0x60, 0xD4, 0xF4)</span></span>
<span class="line"><span>    → 触发 IRQ1 (键盘)       // PS/2 控制器操作产生虚假键盘中断</span></span>
<span class="line"><span>      → irq1_stub</span></span>
<span class="line"><span>        → Keyboard::irq1_handler()</span></span>
<span class="line"><span>          → 编译器生成 movaps %xmm0, (%rsp)  // ← #GP</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p><code>Mouse::init()</code> 通过 8042 PS/2 控制器命令启用 AUX 设备（鼠标）时，控制器状态变化会触发一个虚假的 IRQ1（键盘中断）。这是 PS/2 硬件的已知行为。</p><h2 id="根因分析" tabindex="-1">根因分析 <a class="header-anchor" href="#根因分析" aria-label="Permalink to &quot;根因分析&quot;">​</a></h2><h3 id="x86-64-system-v-abi-栈对齐规则" tabindex="-1">x86_64 System V ABI 栈对齐规则 <a class="header-anchor" href="#x86-64-system-v-abi-栈对齐规则" aria-label="Permalink to &quot;x86_64 System V ABI 栈对齐规则&quot;">​</a></h3><p>调用 <code>call</code> 指令前，RSP 必须 16 字节对齐。<code>call</code> 压入 8 字节返回地址后，被调函数入口处 RSP ≡ 8 (mod 16)。编译器依赖此约定生成 <code>movaps</code> 等 SSE 指令——这些指令要求操作数地址 16 字节对齐。</p><h3 id="isr-stub-原来的栈布局-修复前" tabindex="-1">ISR stub 原来的栈布局（修复前） <a class="header-anchor" href="#isr-stub-原来的栈布局-修复前" aria-label="Permalink to &quot;ISR stub 原来的栈布局（修复前）&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CPU 自动压入 (IRQ):  SS, RSP, RFLAGS, CS, RIP  = 5 × 8 = 40 bytes</span></span>
<span class="line"><span>ISR stub 压入:       error_code(0), rax..r15    = 16 × 8 = 128 bytes</span></span>
<span class="line"><span>                                                        总计 = 168 bytes</span></span>
<span class="line"><span>call handler 压入:   return address                = 8 bytes</span></span>
<span class="line"><span>                                                        总计 = 176 bytes</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>176 是 16 的倍数，意味着 <code>call</code> 之后 handler 入口处 <strong>RSP ≡ 0 (mod 16)</strong>，违反了 System V ABI 要求的 RSP ≡ 8 (mod 16)。</p><p>handler 内部 <code>push %rbx; sub $0x20, %rsp</code> 后 RSP ≡ 8 (mod 16)，此时 <code>movaps %xmm0, (%rsp)</code> 因地址未 16 字节对齐而触发 #GP。</p><h3 id="正确的栈布局-修复后" tabindex="-1">正确的栈布局（修复后） <a class="header-anchor" href="#正确的栈布局-修复后" aria-label="Permalink to &quot;正确的栈布局（修复后）&quot;">​</a></h3><p>在压完 GPR 后额外压入 8 字节对齐 padding：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CPU 自动压入 (IRQ):  SS, RSP, RFLAGS, CS, RIP  = 5 × 8 = 40 bytes</span></span>
<span class="line"><span>ISR stub 压入:       error_code(0), rax..r15    = 16 × 8 = 128 bytes</span></span>
<span class="line"><span>ISR stub 压入:       alignment padding            = 8 bytes</span></span>
<span class="line"><span>                                                        总计 = 176 bytes</span></span>
<span class="line"><span>call handler 压入:   return address                = 8 bytes</span></span>
<span class="line"><span>                                                        总计 = 184 bytes</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>184 ≡ 8 (mod 16)，handler 入口处栈对齐正确。</p><h2 id="修复方案" tabindex="-1">修复方案 <a class="header-anchor" href="#修复方案" aria-label="Permalink to &quot;修复方案&quot;">​</a></h2><p>修改 <code>kernel/arch/x86_64/interrupts.S</code> 中的 <code>ISR_NOERRCODE</code> 和 <code>ISR_ERRCODE</code> 两个宏：</p><div class="language-asm vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    pushq %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">r15</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                        # 最后一个 GPR</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # --- 新增：栈对齐 padding ---</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    pushq </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$0</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                          # alignment padding (8 bytes)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 调整 InterruptFrame* 指针跳过 padding</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    leaq </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(%</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rsp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rdi</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # 指向 padding 之后的 r15（而非 padding 本身）</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    call</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> \\handler</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    addq </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rsp</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                     # 弹出 alignment padding</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    popq %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">r15</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                         # 恢复 GPR（顺序不变）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>关键点：</p><ul><li><code>leaq 8(%rsp), %rdi</code> 确保传递给 C handler 的 <code>InterruptFrame*</code> 指针仍然指向 <code>r15</code> 字段，<code>InterruptFrame</code> 结构体布局无需修改</li><li>handler 返回后 <code>addq $8, %rsp</code> 弹出 padding，再正常恢复 GPR</li></ul><h2 id="为什么之前没触发" tabindex="-1">为什么之前没触发 <a class="header-anchor" href="#为什么之前没触发" aria-label="Permalink to &quot;为什么之前没触发&quot;">​</a></h2><p>这个 bug 一直存在，但之前的 IRQ handler 恰好没有生成 <code>movaps</code> 指令。直到 <code>Keyboard::irq1_handler</code> 中引入了 GUI 双路分发代码（<code>cinux::drivers::Mouse::event_queue().enqueue(gui_ev)</code>），编译器在函数内使用了 XMM 寄存器进行优化，生成了 <code>movaps</code>，才暴露了栈对齐问题。</p><h2 id="经验教训" tabindex="-1">经验教训 <a class="header-anchor" href="#经验教训" aria-label="Permalink to &quot;经验教训&quot;">​</a></h2><ol><li><strong>ISR stub 必须保证栈 16 字节对齐</strong>——这是 x86_64 System V ABI 的硬性要求，不是可选的</li><li><strong>硬件副作用可能触发意外中断</strong>——PS/2 控制器操作可能产生虚假 IRQ，ISR 必须随时能安全执行</li><li><strong>栈对齐 bug 是静默的</strong>——在简单 handler 中不会触发，只有编译器恰好生成 SSE 指令时才会暴露，排查难度较高</li></ol>`,27)])])}const u=a(p,[["render",l]]);export{b as __pageData,u as default};
